#include<bits/stdc++.h>
using namespace std;
long long n,k,a[100005],l,r,mid,id;
bool check(long long x)
{
	id=0;
	for(int i=1;i<=n;i++)
	{
		id+=a[i]/x;
	}
//	cout<<id<<" ";
	return id>=k;
}
int main()
{
	cin>>n>>k;
//	cout<<k<<"\n";
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		r=max(r,a[i]);
	}
	l=1;
//	for(int i=100;i<=120;i++)
//	{
//		cout<<i<<" "<<check(i)<<"\n";
//	}
	while(l<r)
	{
		mid=l+(r-l)/2;
		if(!check(mid))	r=mid;
		else	l=mid+1;
	}
	cout<<l-1;
	return 0;
}
